const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const PREMBLY_BASE_URL = process.env.PREMBLY_BASE_URL || 'https://api.prembly.com';
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID || '';
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY || '';

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

app.post('/verify-nin', async (req, res) => {
  const { nin } = req.body;

  let retries = 0;
  let delay = 100;

  while (retries <= 3) {
    try {
      const response = await axios.post(
        `${PREMBLY_BASE_URL}/verification/nin`,
        { nin },
        {
          headers: {
            'app-id': PREMBLY_APP_ID,
            'x-api-key': PREMBLY_API_KEY,
            'Content-Type': 'application/json',
          },
        }
      );
      return res.status(200).json(response.data);
    } catch (error) {
      if (error.response && error.response.status === 429) {
        if (retries === 3) {
          return res.status(429).send('Rate limit exceeded, please try again later');
        }
        await sleep(delay);
        delay *= 2;
        retries++;
      } else {
        const status = error.response ? error.response.status : 500;
        const data = error.response ? error.response.data : { error: 'Internal Server Error' };
        return res.status(status).json(data);
      }
    }
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

